class Playground {
    async run(inputs) {
        // 1. Parse Inputs
        const nums = inputs[0].split(',').map(n => parseInt(n.trim())).filter(n => !isNaN(n));
        const k = parseInt(inputs[1]);

        if (isNaN(k) || k <= 0 || k > nums.length) {
            this.log("Invalid value for K");
            return "Invalid K";
        }

        // 2. Initialize Visualizers
        this.inputArray.init(nums);
        this.minHeap.init([], 'min');
        this.variables.init([
            ["k", k],
            ["elements_extracted", 0],
            ["current_min", "null"]
        ]);
        this.log(`Finding the ${k}th smallest element...`);
        await this.await();

        // 3. Build the Min Heap
        this.log("Building Min Heap by inserting all elements from the array.");
        for (let i = 0; i < nums.length; i++) {
            const val = nums[i];
            this.inputArray.highlight(i, "#00e0ff");
            this.minHeap.push(val);
            this.log(`Inserted ${val} into the Min Heap`);
            await this.await();
            this.inputArray.highlight(i, null);
        }

        // 4. Extract k-1 elements
        this.log(`Now we extract the minimum element ${k - 1} times.`);
        for (let i = 1; i < k; i++) {
            const extracted = this.minHeap.pop();
            this.variables.put("elements_extracted", i);
            this.variables.put("current_min", extracted);
            this.log(`Extraction ${i}: Popped ${extracted} (The current smallest)`);
            await this.await();
        }

        // 5. Peek the result
        const result = this.minHeap.peek();
        this.variables.put("current_min", result);
        this.minHeap.highlight(0, "#00f5a0");
        this.log(`The ${k}th smallest element is the root of the heap: ${result}`);
        await this.await();

        return result;
    }
}
